#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int R1, W1, C1, R2, W2, C2;
        scanf("%d %d %d", &R1, &W1, &C1);
        scanf("%d %d %d", &R2, &W2, &C2);
        int a = 0, b = 0;
        if (R1 > R2) a++; else b++;
        if (W1 > W2) a++; else b++;
        if (C1 > C2) a++; else b++;
        if (a > b) printf("A\n"); else printf("B\n");
    }
    return 0;
}

