import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            StringTokenizer st1 = new StringTokenizer(br.readLine());
            int R1 = Integer.parseInt(st1.nextToken());
            int W1 = Integer.parseInt(st1.nextToken());
            int C1 = Integer.parseInt(st1.nextToken());
            StringTokenizer st2 = new StringTokenizer(br.readLine());
            int R2 = Integer.parseInt(st2.nextToken());
            int W2 = Integer.parseInt(st2.nextToken());
            int C2 = Integer.parseInt(st2.nextToken());
            int a = 0, b = 0;
            if (R1 > R2) a++; else b++;
            if (W1 > W2) a++; else b++;
            if (C1 > C2) a++; else b++;
            sb.append(a > b ? "A" : "B").append('\n');
        }
        System.out.print(sb.toString());
    }
}

